(function() {
  'use strict';
  const STORAGE_KEY = 'ledger-state-2026-05-21-v2';
  const NS_KEY = 'ledger-north-star-v2-2026-05-21-v2';
  const STATUS_CYCLE = ['on-track', 'drifting', 'blocked', 'paused'];
  const STATUS_LABEL = { 'on-track':'on track','drifting':'drifting','blocked':'blocked','paused':'paused' };
  const NS_TITLE_BY_ID = {
    'family':'Elca · the children · the home','matterhorn':'Matterhorn','chronos':'Chronos',
    'spock':'Spock','portfolio':'Portfolio','inner-life':'Inner life','flywheel':'Financial Flywheel'
  };
  const DECISION_EXPIRE_DAYS = 5;

  let state = { done:{}, comments:{}, inboxHandled:{}, draftGuidance:{}, decisionsDismissed:{},
                userTasks:[], inboxPromoted:[], bucketDone:{} };
  try { state = Object.assign(state, JSON.parse(localStorage.getItem(STORAGE_KEY)||'{}')); } catch(e) {}
  for (const k of ['done','comments','inboxHandled','draftGuidance','decisionsDismissed','bucketDone']) if (!state[k]) state[k]={};
  for (const k of ['userTasks','inboxPromoted']) if (!state[k]) state[k]=[];

  let nsState = { items:{}, order:[], lastCalibrated:null, addedToday:[] };
  try { nsState = Object.assign(nsState, JSON.parse(localStorage.getItem(NS_KEY)||'{}')); } catch(e) {}
  if (!nsState.items) nsState.items={};
  if (!nsState.order) nsState.order=[];
  if (!nsState.addedToday) nsState.addedToday=[];

  const save   = () => { try { localStorage.setItem(STORAGE_KEY, JSON.stringify(state)); } catch(e){} };
  const saveNS = () => { try { localStorage.setItem(NS_KEY, JSON.stringify(nsState)); } catch(e){} };
  const escapeHtml = s => (s||'').replace(/[&<>"']/g, c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
  const daysAgo = iso => { try { return Math.floor((new Date('2026-05-15') - new Date(iso))/86400000); } catch(e){return 0;} };

  function hydrateNS() {
    document.querySelectorAll('.ns-card').forEach(card => {
      const id = card.dataset.nsId;
      const titleEl = card.querySelector('.ns-card-title');
      const bodyEl  = card.querySelector('.ns-card-body');
      const nbaEl   = card.querySelector('.ns-nba');
      const statusEl= card.querySelector('.ns-status');
      const noteEl  = card.querySelector('.ns-note');
      if (!nsState.items[id] || !nsState.items[id]._seed) {
        nsState.items[id] = nsState.items[id] || {};
        nsState.items[id]._seed = { title: titleEl.textContent.trim(), body: bodyEl.textContent.trim(),
          nba: nbaEl ? nbaEl.textContent.trim() : '', status: statusEl.dataset.status };
      }
      const s = nsState.items[id];
      if (s.title) titleEl.textContent = s.title;
      if (s.body)  bodyEl.textContent  = s.body;
      if (nbaEl && s.nba) nbaEl.textContent = s.nba;
      if (s.status) { statusEl.dataset.status = s.status; statusEl.textContent = STATUS_LABEL[s.status]; }
      if (s.note) { noteEl.value = s.note; card.querySelector('.ns-control-btn')?.classList.add('has-note'); }
      if (!nsState.order.includes(id)) nsState.order.push(id);
      const bind = (el, key) => el && el.addEventListener('input', () => {
        nsState.items[id] = nsState.items[id]||{}; nsState.items[id][key] = el.textContent.trim();
        nsState.items[id].editedAt = new Date().toISOString(); saveNS(); updateMeta();
      });
      bind(titleEl, 'title'); bind(bodyEl, 'body'); bind(nbaEl, 'nba');
      if (noteEl) noteEl.addEventListener('input', () => {
        nsState.items[id] = nsState.items[id]||{};
        const val = noteEl.value.trim();
        if (val) nsState.items[id].note = val; else delete nsState.items[id].note;
        card.querySelector('.ns-control-btn')?.classList.toggle('has-note', !!val);
        saveNS(); updateMeta();
      });
    });
    saveNS();
  }

  function hydrateDaily() {
    document.querySelectorAll('[data-id]').forEach(el => {
      const id = el.dataset.id;
      if (state.done[id]) { el.classList.add('done'); el.querySelector('.tick, .tick-small')?.classList.add('done'); }
      if (state.inboxHandled[id]) el.classList.add('handled');
      if (state.bucketDone[id]) el.classList.add('done');
      const input = el.querySelector('.comment-input'); const toggle = el.querySelector('.comment-toggle');
      if (input && state.comments[id]) { input.value = state.comments[id]; toggle?.classList.add('has-comment'); }
      const di = el.querySelector('.inbox-draft-input'); const db = el.querySelector('.inbox-draft-btn');
      if (di && state.draftGuidance[id]) { di.value = state.draftGuidance[id]; db?.classList.add('has-guidance'); }
      if (di) di.addEventListener('input', () => {
        const v = di.value.trim();
        if (v) state.draftGuidance[id] = v; else delete state.draftGuidance[id];
        db?.classList.toggle('has-guidance', !!v); save(); updateMeta();
      });
    });
  }

  function hydrateDecisions() {
    document.querySelectorAll('.decision-item').forEach(item => {
      const id = item.dataset.decisionId, dateStr = item.dataset.decisionDate;
      if (state.decisionsDismissed[id]) { item.style.display='none'; return; }
      const age = daysAgo(dateStr);
      item.querySelector('.decision-age').textContent = age <= 0 ? 'today' : `${age}d ago`;
      if (age >= DECISION_EXPIRE_DAYS) {
        item.style.display='none';
        state.decisionsDismissed[id] = { auto:true, dismissedAt: new Date().toISOString() }; save();
      } else if (age >= DECISION_EXPIRE_DAYS - 2) item.classList.add('expiring');
    });
    if (Array.from(document.querySelectorAll('.decision-item')).every(i => i.style.display === 'none')) {
      const s = document.querySelector('.decisions'); if (s) s.style.display = 'none';
    }
  }

  function restoreUserTasks() {
    const grid = document.getElementById('priority-grid');
    state.userTasks.forEach(t => { if (!document.querySelector(`[data-id="${t.id}"]`)) grid.appendChild(buildCard(t)); });
    state.inboxPromoted.forEach(p => { if (!document.querySelector(`[data-id="${p.id}"]`)) grid.appendChild(buildCard(p)); });
    nsState.addedToday.forEach(nsId => {
      const promoteId = 'ns-' + nsId;
      if (document.querySelector(`[data-id="${promoteId}"]`)) return;
      const item = nsState.items[nsId];
      const nba = item && (item.nba || item._seed?.nba);
      const title = item && (item.title || item._seed?.title) || NS_TITLE_BY_ID[nsId];
      const body = nba || (item && (item.body || item._seed?.body)) || '';
      grid.appendChild(buildCard({ id: promoteId, title, body, kind: 'from-north-star',
        meta: '★ from North Star · ' + (NS_TITLE_BY_ID[nsId] || nsId), northStar: nsId, actionUrl: '' }));
    });
  }

  function buildCard(task) {
    const div = document.createElement('div');
    div.className = 'card ' + (task.kind === 'from-north-star' ? 'from-north-star' : 'user-added');
    div.dataset.id = task.id; div.dataset.title = task.title;
    if (task.actionUrl) div.dataset.actionUrl = task.actionUrl;
    if (task.northStar) div.dataset.northStar = task.northStar;
    if (task.bucket) div.dataset.bucket = task.bucket;
    const tagHtml = task.northStar
      ? `<span class="ns-tag" title="Serves: ${escapeHtml(NS_TITLE_BY_ID[task.northStar]||task.northStar)}">${escapeHtml((NS_TITLE_BY_ID[task.northStar]||task.northStar).split(' · ')[0])}</span>` : '';
    const tickLabel = task.kind === 'from-north-star' ? 'Action taken' : 'Mark done';
    const workBtn = task.actionUrl
      ? `<a class="work-btn" href="${escapeHtml(task.actionUrl)}" target="_blank" onclick="workOnThis(event, this)">→ Work on this</a>`
      : `<button class="work-btn" onclick="workOnThis(event, this)">→ Work on this</button>`;
    div.innerHTML = `
      <div class="card-head"><div class="card-title">${escapeHtml(task.title)}</div>${tagHtml}</div>
      <div class="card-meta">${escapeHtml(task.meta || 'added today')}${task.bucket?` · → ${task.bucket}`:''}</div>
      <div class="card-body">${escapeHtml(task.body || '')}</div>
      <div class="card-controls">
        <div class="tick" onclick="toggleDone(this)" title="${tickLabel}"></div>
        <span class="control-label">${tickLabel}</span>
        ${workBtn}
        <button class="comment-toggle" onclick="toggleComment(this)">Add note</button>
      </div>
      <div class="comment-box"><textarea class="comment-input" placeholder="Note for Claude…" oninput="saveComment(this)"></textarea></div>`;
    return div;
  }

  window.toggleDone = function(t) {
    const card = t.closest('[data-id]'); const id = card.dataset.id;
    state.done[id] = !state.done[id];
    card.classList.toggle('done', state.done[id]); t.classList.toggle('done', state.done[id]);
    save(); updateMeta();
  };
  window.toggleRow = function(t) {
    const r = t.closest('[data-id]'); const id = r.dataset.id;
    state.done[id] = !state.done[id]; r.classList.toggle('done', state.done[id]);
    save(); updateMeta();
  };
  window.toggleBucket = function(t) {
    const r = t.closest('[data-id]'); const id = r.dataset.id;
    state.bucketDone[id] = !state.bucketDone[id]; r.classList.toggle('done', state.bucketDone[id]);
    save(); updateMeta();
  };
  window.toggleComment = function(btn) {
    const c = btn.closest('[data-id]'); const box = c.querySelector('.comment-box');
    box.classList.toggle('open'); if (box.classList.contains('open')) box.querySelector('.comment-input').focus();
  };
  window.saveComment = function(input) {
    const c = input.closest('[data-id]'); const id = c.dataset.id; const v = input.value.trim();
    if (v) state.comments[id] = v; else delete state.comments[id];
    c.querySelector('.comment-toggle')?.classList.toggle('has-comment', !!v); save(); updateMeta();
  };
  window.workOnThis = function(event, el) {
    const card = el.closest('[data-id]'); const url = card.dataset.actionUrl;
    if (url) return;
    event.preventDefault();
    const title = card.dataset.title || ''; const body = card.querySelector('.card-body, .b-text')?.textContent.trim() || '';
    const prompt = `Help me work on this: **${title}**\n\nContext:\n${body}\n\nWhat's the smartest first move?`;
    navigator.clipboard.writeText(prompt).then(() => {
      window.open('https://claude.ai/new', '_blank');
      showToast('Prompt copied. Claude opening — paste to start.');
    });
  };
  window.toggleInbox = function(t) {
    const it = t.closest('.inbox-item'); const id = it.dataset.id;
    state.inboxHandled[id] = !state.inboxHandled[id];
    it.classList.toggle('handled', state.inboxHandled[id]); save(); updateMeta();
  };
  window.toggleDraft = function(b) {
    const it = b.closest('.inbox-item'); const d = it.querySelector('.inbox-draft');
    d.classList.toggle('open'); if (d.classList.contains('open')) d.querySelector('.inbox-draft-input').focus();
  };
  window.promoteInbox = function(b) {
    const it = b.closest('.inbox-item'); const id = it.dataset.id;
    if (state.inboxPromoted.find(p => p.id === id+'-promoted')) { showToast('Already on Front Page.'); return; }
    const promo = { id: id+'-promoted', title: it.dataset.title, body: it.querySelector('.inbox-text').textContent.trim(),
      actionUrl: it.dataset.actionUrl, kind:'user-added', meta:'↑ from Inbox' };
    state.inboxPromoted.push(promo); document.getElementById('priority-grid').appendChild(buildCard(promo));
    save(); showToast('Added to Front Page.'); updateMeta();
  };
  window.dismissDecision = function(b) {
    const it = b.closest('.decision-item'); state.decisionsDismissed[it.dataset.decisionId] = { manual:true, dismissedAt: new Date().toISOString() };
    it.style.display = 'none'; save();
    if (Array.from(document.querySelectorAll('.decision-item')).every(i => i.style.display === 'none'))
      document.querySelector('.decisions').style.display = 'none';
    updateMeta();
  };
  window.cycleStatus = function(el) {
    const next = STATUS_CYCLE[(STATUS_CYCLE.indexOf(el.dataset.status||'on-track')+1) % STATUS_CYCLE.length];
    el.dataset.status = next; el.textContent = STATUS_LABEL[next];
    const id = el.closest('.ns-card').dataset.nsId;
    nsState.items[id] = nsState.items[id]||{}; nsState.items[id].status = next;
    nsState.items[id].editedAt = new Date().toISOString(); saveNS(); updateMeta();
  };
  window.toggleNSNote = function(b) {
    const n = b.closest('.ns-card').querySelector('.ns-note');
    n.classList.toggle('open'); if (n.classList.contains('open')) n.focus();
  };
  window.promoteNS = function(b) {
    const c = b.closest('.ns-card'); const id = c.dataset.nsId;
    if (nsState.addedToday.includes(id)) { showToast('Already promoted.'); return; }
    const title = c.querySelector('.ns-card-title').textContent.trim();
    const nba   = c.querySelector('.ns-nba')?.textContent.trim();
    const body  = c.querySelector('.ns-card-body').textContent.trim();
    nsState.addedToday.push(id); saveNS();
    document.getElementById('priority-grid').appendChild(buildCard({
      id: 'ns-'+id, title, body: nba || body, kind: 'from-north-star', northStar: id,
      meta: '★ from North Star · promoted ' + new Date().toLocaleTimeString('en-GB',{hour:'2-digit',minute:'2-digit'}),
    }));
    showToast('Promoted. "Action taken" logs against the star, not closing it.');
    updateMeta();
  };
  window.addNS = function() {
    const id = 'custom-' + Date.now().toString(36); const g = document.getElementById('ns-grid');
    const rank = g.querySelectorAll('.ns-card').length + 1;
    const c = document.createElement('div'); c.className='ns-card'; c.dataset.nsId = id;
    c.innerHTML = `<div class="ns-card-head"><div class="ns-rank">${rank}</div><div class="ns-card-title" contenteditable="true">New North Star — click to name</div><div class="ns-status" data-status="on-track" onclick="cycleStatus(this)">on track</div></div><div class="ns-card-body" contenteditable="true"></div><div class="ns-nba-row"><span class="ns-nba-label">Next:</span><div class="ns-nba" contenteditable="true"></div></div><div class="ns-card-controls"><button class="ns-control-btn" onclick="toggleNSNote(this)">Note</button><button class="ns-control-btn promote" onclick="promoteNS(this)">↑ Promote to today</button></div><textarea class="ns-note"></textarea>`;
    g.appendChild(c); nsState.order.push(id);
    nsState.items[id] = { _seed: { title:'New North Star — click to name', body:'', nba:'', status:'on-track' } };
    saveNS(); hydrateNS(); c.querySelector('.ns-card-title').focus();
  };
  window.recalibrate = function() {
    nsState.lastCalibrated = new Date().toISOString(); saveNS();
    document.getElementById('ns-last-calibrated').textContent =
      'Last calibrated ' + new Date().toLocaleDateString('en-GB',{day:'numeric',month:'short',year:'numeric'});
    showToast('Marked recalibrated.'); updateMeta();
  };
  window.openAddTask = function() {
    document.getElementById('add-task-modal').classList.add('open');
    setTimeout(()=>document.getElementById('add-task-title').focus(), 50);
  };
  window.closeAddTask = function() {
    document.getElementById('add-task-modal').classList.remove('open');
    ['add-task-title','add-task-body','add-task-ns','add-task-bucket'].forEach(i => document.getElementById(i).value='');
  };
  window.submitAddTask = function() {
    const title = document.getElementById('add-task-title').value.trim();
    if (!title) { showToast('Task needs a title.'); return; }
    const body = document.getElementById('add-task-body').value.trim();
    const ns = document.getElementById('add-task-ns').value;
    const bucket = document.getElementById('add-task-bucket').value;
    const id = 'task-' + Date.now().toString(36);
    const task = { id, title, body, kind:'user-added', northStar: ns || null, bucket: bucket || null, meta: 'added today' };
    state.userTasks.push(task);
    document.getElementById('priority-grid').appendChild(buildCard(task));
    save(); closeAddTask(); showToast('Task added.'); updateMeta();
  };

  document.addEventListener('keydown', e => {
    if (e.target.matches('input, textarea, [contenteditable="true"]')) return;
    if (e.key === 't' || e.key === 'T') { e.preventDefault(); openAddTask(); }
    if (e.key === 'Escape') closeAddTask();
    if ((e.key === 's' || e.key === 'S') && (e.metaKey || e.ctrlKey)) { e.preventDefault(); sendToClaude(); }
  });

  function nsChangeCount() {
    let n = 0;
    Object.entries(nsState.items).forEach(([id, it]) => {
      if (!it._seed) return;
      if (it.title  && it.title  !== it._seed.title)  n++;
      if (it.body   && it.body   !== it._seed.body)   n++;
      if (it.nba    && it.nba    !== (it._seed.nba||'')) n++;
      if (it.status && it.status !== it._seed.status) n++;
      if (it.note) n++;
    });
    n += nsState.addedToday.length;
    if (nsState.lastCalibrated && new Date(nsState.lastCalibrated).toDateString() === new Date().toDateString()) n++;
    return n;
  }
  function updateMeta() {
    const items = document.querySelectorAll('[data-id]'); const total = items.length;
    let done=0, comments=0, handled=0, drafts=0, bucketDone=0;
    items.forEach(el => {
      const id = el.dataset.id;
      if (state.done[id]) done++;
      if (state.comments[id]) comments++;
      if (state.inboxHandled[id]) handled++;
      if (state.draftGuidance[id]) drafts++;
      if (state.bucketDone[id]) bucketDone++;
    });
    const pct = total === 0 ? 0 : Math.round((done/total)*100);
    document.getElementById('progress-text').textContent = `${done} of ${total} cleared`;
    document.getElementById('comments-text').textContent = `${comments} note${comments===1?'':'s'}`;
    document.getElementById('progress-fill').style.width = `${pct}%`;
    const ns = nsChangeCount();
    document.getElementById('ns-changes-text').textContent = ns === 0 ? 'North Star clean' : `${ns} North Star change${ns===1?'':'s'}`;
    document.getElementById('bucket-actions-text').textContent = `${bucketDone} bucket action${bucketDone===1?'':'s'}`;
    const nsMeta = document.getElementById('ns-meta');
    const cc = document.querySelectorAll('.ns-card').length;
    if (nsMeta) nsMeta.textContent = ns > 0 ? `${cc} priorities · ${ns} unsynced` : `${cc} priorities · synced`;
    const tasks = state.userTasks.length + state.inboxPromoted.length;
    const total2 = done + comments + handled + drafts + ns + tasks + bucketDone;
    const badge = document.getElementById('send-badge'); const btn = document.getElementById('send-btn');
    badge.textContent = total2; btn.classList.toggle('empty', total2 === 0);
  }

  window.sendToClaude = function() {
    const items = document.querySelectorAll('[data-id]');
    const done=[], comments=[], inboxHandled=[], drafts=[], bucketActions=[];
    items.forEach(el => {
      const id = el.dataset.id;
      const title = el.dataset.title || el.querySelector('.card-title, .row-title, .inbox-text, .b-text')?.textContent.trim() || id;
      const ns = el.dataset.northStar || null;
      const bucket = el.dataset.bucket || null;
      if (state.done[id]) done.push({ id, title, northStar: ns, isPromotedNS: id.startsWith('ns-') });
      if (state.comments[id]) comments.push({ id, title, comment: state.comments[id], northStar: ns });
      if (state.inboxHandled[id]) inboxHandled.push({ id, title });
      if (state.draftGuidance[id]) drafts.push({ id, title, guidance: state.draftGuidance[id], url: el.dataset.actionUrl||'' });
      if (state.bucketDone[id] && bucket) bucketActions.push({ id, title, bucket, url: el.dataset.actionUrl||'' });
    });
    const nsChanges = [];
    Object.entries(nsState.items).forEach(([id, it]) => {
      if (!it._seed) return;
      const diff = {};
      if (it.title  && it.title  !== it._seed.title)  diff.title  = { from: it._seed.title, to: it.title };
      if (it.body   && it.body   !== it._seed.body)   diff.body   = { from: it._seed.body, to: it.body };
      if (it.nba    && it.nba    !== (it._seed.nba||'')) diff.nba = { from: it._seed.nba||'', to: it.nba };
      if (it.status && it.status !== it._seed.status) diff.status = { from: it._seed.status, to: it.status };
      if (it.note) diff.note = it.note;
      if (Object.keys(diff).length) nsChanges.push({ id, ...diff });
    });
    const promotedNS = nsState.addedToday.map(id => ({ id, item: nsState.items[id] }));
    const newTasks = state.userTasks.slice();
    const promotedInbox = state.inboxPromoted.slice();
    const dismissedManual = Object.entries(state.decisionsDismissed).filter(([_,v])=>v.manual).map(([k])=>k);

    const total = done.length + comments.length + inboxHandled.length + drafts.length + nsChanges.length + promotedNS.length + newTasks.length + promotedInbox.length + dismissedManual.length + bucketActions.length;
    if (total === 0) { showToast('Nothing to send yet.'); return; }

    const dt = new Date().toISOString().slice(0,16).replace('T',' ') + ' UTC';
    let p = `# Dashboard Updates · Stellenbosch Ledger · ${dt}\n\n`;

    if (done.length) {
      p += `## Items marked done (${done.length})\n`;
      done.forEach(({id,title,northStar,isPromotedNS}) => {
        if (isPromotedNS) p += `- **Action taken against North Star** [${id.replace(/^ns-/,'')}]: ${title} \`[${id}]\`\n`;
        else p += `- **${title}** \`[${id}]\`${northStar?` _(serves ${northStar})_`:''}\n`;
      });
      p += '\n';
    }
    if (bucketActions.length) {
      p += `## Bucket actions completed (${bucketActions.length})\n`;
      const byBucket = {};
      bucketActions.forEach(b => { (byBucket[b.bucket]=byBucket[b.bucket]||[]).push(b); });
      Object.entries(byBucket).forEach(([bk, items]) => {
        p += `### ${bk}\n`;
        items.forEach(({id,title,url}) => p += `- ${title} \`[${id}]\`${url?` ([source](${url}))`:''}\n`);
      });
      p += '\n';
    }
    if (comments.length) {
      p += `## Notes added (${comments.length})\n`;
      comments.forEach(({id,title,comment,northStar}) => p += `- **${title}** \`[${id}]\`${northStar?` _(serves ${northStar})_`:''}:\n  > ${comment.split('\n').join('\n  > ')}\n`);
      p += '\n';
    }
    if (inboxHandled.length) { p += `## Inbox marked handled (${inboxHandled.length})\n`; inboxHandled.forEach(({id,title})=>p+=`- **${title}** \`[${id}]\`\n`); p+='\n'; }
    if (drafts.length) {
      p += `## Draft replies requested (${drafts.length})\n`;
      drafts.forEach(({id,title,guidance,url}) => p += `- **${title}** \`[${id}]\`${url?` ([thread](${url}))`:''}\n  > ${guidance.split('\n').join('\n  > ')}\n`);
      p += '\n';
    }
    if (nsChanges.length) {
      p += `## North Star changes (${nsChanges.length})\n`;
      nsChanges.forEach(c => {
        p += `- **${c.id}**\n`;
        if (c.title)  p += `    - **Title**: "${c.title.from}" → "${c.title.to}"\n`;
        if (c.body)   p += `    - **Body**\n        - from: ${c.body.from}\n        - to: ${c.body.to}\n`;
        if (c.nba)    p += `    - **Next best action**: "${c.nba.from}" → "${c.nba.to}"\n`;
        if (c.status) p += `    - **Status**: ${c.status.from} → ${c.status.to}\n`;
        if (c.note)   p += `    - **Note**: ${c.note}\n`;
      });
      p += '\n';
    }
    if (promotedNS.length) { p += `## North Stars promoted to today (${promotedNS.length})\n`; promotedNS.forEach(({id,item})=>p+=`- **${id}** — "${item?.title || item?._seed?.title || id}"\n`); p+='\n'; }
    if (newTasks.length) {
      p += `## New tasks added (${newTasks.length})\n`;
      newTasks.forEach(t => {
