(function() {
  'use strict';
  // ── Tab navigation + stale-data banner ──
  //  Tabs are buttons with id of the form [tab-NAME] paired to panels [panel-NAME].
  //  v1.69 (15 Jun 2026) — Do This Now retired; Front Page is now the leftmost + default tab.
