  var TAB_NAMES = ['front-page','deep-work','isa','people','north-stars','everything-else','done'];
  window.showTab = function(name) {
    if (TAB_NAMES.indexOf(name) === -1) name = DEFAULT_TAB;
    document.querySelectorAll('.tab-btn').forEach(function(b){ b.classList.remove('active'); });
    document.querySelectorAll('.tab-panel').forEach(function(p){ p.classList.remove('active'); });
    var btn = document.getElementById('tab-' + name);
    var panel = document.getElementById('panel-' + name);
    if (btn) btn.classList.add('active');
    if (panel) panel.classList.add('active');
    try { localStorage.setItem(TAB_KEY, name); } catch(e) {}
  };
  function initTab() {
    var stored = DEFAULT_TAB;
    try { stored = localStorage.getItem(TAB_KEY) || DEFAULT_TAB; } catch(e) {}
    // Defensive: if stored is a retired tab name, fall back to default
    if (TAB_NAMES.indexOf(stored) === -1) stored = DEFAULT_TAB;
    window.showTab(stored);
  }
  // ── Stale-data banner: shows above tabs when last fire was >12h ago ──
  function initStaleBanner() {
    var body = document.body;
    var stamp = body && body.getAttribute('data-compiled-at');
    var banner = document.getElementById('stale-banner');
    var txt = document.getElementById('stale-text');
    if (!stamp || !banner || !txt) return;
    var compiled = new Date(stamp);
    if (isNaN(compiled.getTime())) return;
    var now = new Date();
    var hoursOld = (now.getTime() - compiled.getTime()) / (1000 * 60 * 60);
    if (hoursOld < 12) return;
    var ageStr;
    if (hoursOld < 48) {
      ageStr = Math.round(hoursOld) + 'h';
    } else {
      ageStr = Math.round(hoursOld / 24) + ' days';
    }
    var compiledStr = compiled.toLocaleString('en-GB', { weekday:'short', day:'numeric', month:'short', hour:'2-digit', minute:'2-digit' });
    txt.innerHTML = '<strong>' + ageStr + ' stale</strong> — last refreshed ' + compiledStr + ' SAST. The cron likely missed fires (Mac may have been asleep).';
    banner.style.display = 'flex';
  }
  function init() {
    initTab();
    initStaleBanner();
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();

(function() {
  'use strict';
  // ── Chief-of-Staff question interactivity (added 19 Jun 2026) ──
  //  Wire up the .q-option buttons inside #cos-question-band so Roger can
  //  answer Q-N inline. The selected button flips to .selected; the answer
  //  is captured into data-answered + data-answer-text on the band itself
  //  (plus localStorage so a reload doesn't lose it). sendToClaude reads
  //  data-answered and folds the answer into the next payload.
  var COS_KEY = 'ledger-cos-answers';
  window.answerCosQuestion = function(btn, letter) {
    var band = document.getElementById('cos-question-band');
    if (!band) return;
    var qidMatch = band.querySelector('.cos-count');
    var qid = (qidMatch && qidMatch.textContent.match(/Q-\d+/)) ? qidMatch.textContent.match(/Q-\d+/)[0] : 'Q-?';
    var freeText = '';
    if (letter === 'c' || (btn.textContent || '').trim().toLowerCase().indexOf('other') === 0) {
      freeText = window.prompt('Your answer (Roger):', '') || '';
    }
    // visually mark
    band.querySelectorAll('.q-option').forEach(function(b){ b.classList.add('disabled'); b.classList.remove('selected'); });
    btn.classList.remove('disabled');
    btn.classList.add('selected');
    band.setAttribute('data-answered', letter);
    band.setAttribute('data-answer-text', freeText);
    // ack message
    var existingAck = band.querySelector('.q-ack');
    if (existingAck) existingAck.remove();
    var ack = document.createElement('div');
    ack.className = 'q-ack';
    ack.textContent = '✓ Answer captured (' + letter.toUpperCase() + ')' + (freeText ? ' — note: ' + freeText : '') + '. Tap "Send to Claude" to fly it back, or it ships with the next payload.';
    band.appendChild(ack);
    // persist
    try {
      var cur = JSON.parse(localStorage.getItem(COS_KEY) || '{}');
      cur[qid] = { letter: letter, freeText: freeText, ts: new Date().toISOString(), label: (btn.textContent || '').trim() };
      localStorage.setItem(COS_KEY, JSON.stringify(cur));
    } catch(e) {}
    // bump the Send-to-Claude badge — sendToClaude payload includes the answer now
    if (window.updateMeta) try { window.updateMeta(); } catch(e) {}
  };
  function wireQOptions() {
    var band = document.getElementById('cos-question-band');
    if (!band) return;
    var btns = band.querySelectorAll('.q-option');
    btns.forEach(function(btn, i) {
      if (btn.dataset.wired) return;
      btn.dataset.wired = '1';
      var letter = String.fromCharCode(97 + i); // a, b, c
      btn.addEventListener('click', function(){ window.answerCosQuestion(btn, letter); });
    });
    // restore answered state from localStorage on load
    try {
      var qidMatch = band.querySelector('.cos-count');
      var qid = (qidMatch && qidMatch.textContent.match(/Q-\d+/)) ? qidMatch.textContent.match(/Q-\d+/)[0] : 'Q-?';
      var cur = JSON.parse(localStorage.getItem(COS_KEY) || '{}');
      if (cur[qid]) {
        var entry = cur[qid];
        band.setAttribute('data-answered', entry.letter);
        band.setAttribute('data-answer-text', entry.freeText || '');
        // mark the matching button
        var ix = ['a','b','c','d','e'].indexOf(entry.letter);
        if (ix >= 0 && btns[ix]) {
          btns.forEach(function(b){ b.classList.add('disabled'); });
          btns[ix].classList.remove('disabled');
          btns[ix].classList.add('selected');
        }
        if (!band.querySelector('.q-ack')) {
          var ack = document.createElement('div');
          ack.className = 'q-ack';
          ack.textContent = '✓ Answer captured (' + entry.letter.toUpperCase() + ')' + (entry.freeText ? ' — note: ' + entry.freeText : '') + ' on ' + new Date(entry.ts).toLocaleString('en-GB',{day:'numeric',month:'short',hour:'2-digit',minute:'2-digit'}) + '. Carrying in next Send-to-Claude payload.';
          band.appendChild(ack);
        }
      }
    } catch(e) {}
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', wireQOptions);
  } else {
    wireQOptions();
  }
})();

(function() { 'use strict';
