  g.querySelectorAll('.card').forEach(dec);
  new MutationObserver(ms=>ms.forEach(m=>m.addedNodes.forEach(n=>{if(n.nodeType===1 && n.classList && n.classList.contains('card')) dec(n);}))).observe(g,{childList:true});
  let dr=null;
