  g.addEventListener('drop',e=>{e.preventDefault(); const t=e.target.closest('.card'); if (!t||!dr||t===dr) return; const r=t.getBoundingClientRect(); t.parentNode.insertBefore(dr,(e.clientY-r.top)>r.height/2?t.nextSibling:t); t.classList.remove('drag-over'); po();});
  function po() { fp.order=Array.from(g.querySelectorAll('.card')).map(c=>c.dataset.id).filter(Boolean); save(); updateMeta(); }
  if (fp.order && fp.order.length) { const byId={}; g.querySelectorAll('.card').forEach(c=>{if(c.dataset.id) byId[c.dataset.id]=c;}); fp.order.forEach(id=>{if(byId[id]) g.appendChild(byId[id]);}); }
  const o=window.sendToClaude;
  window.sendToClaude=function(){
