      let x='\n\n## Front Page edits (v1.5)\n';
      es.forEach(e=>{x+=`- \`[${e.id}]\`\n`; if(e.newTitle) x+=`    - **Title**: "${e.origTitle}" → "${e.newTitle}"\n`; if(e.newBody) x+=`    - **Body**\n        - from: ${e.origBody}\n        - to: ${e.newBody}\n`;});
      x+='\n### Front Page order (top→bottom)\n';
      or.forEach((o,i)=>x+=`${i+1}. **${o.title}** \`[${o.id}]\`${o.ns?` _(serves ${o.ns})_`:''}\n`);
      x+='\n### Sync rules for Notion Actions DB\n1. Dedupe by fuzzy title (≥0.85). Do NOT duplicate.\n2. Edits → UPDATE matched Action. Unmatched → CREATE tagged with NS + Front Page provenance.\n3. Order = priority. Write back as Priority Rank.\n4. Marked Done is authoritative.\n5. Echo back what was updated/created/marked Done.\n';
      p=p.replace(/\n*Confirm in chat when done\.\s*$/, x+'\nConfirm in chat when done.');
